import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // ── Quote: Empty / Base Premiums ──────────────────────────────────

  it.todo(
    "quote with empty item list should return premium 5 G (processing fee only)"
  );

  it.todo(
    "quote for a single sword should return premium 115 G (100 base + 10 first-insurance + 5 fee)"
  );

  it.todo(
    "quote for a single amulet should return premium 71 G (60 base + 6 first-insurance + 5 fee)"
  );

  it.todo(
    "quote for a single staff should return premium 93 G (80 base + 8 first-insurance + 5 fee)"
  );

  it.todo(
    "quote for a single potion should return premium 49 G (40 base + 4 first-insurance + 5 fee)"
  );

  // ── Quote: Component Premiums ─────────────────────────────────────

  it.todo(
    "quote for 2 runes should have 50 G base premium (2 x 25 G, no block)"
  );

  it.todo(
    "quote for 3 runes should have 60 G base premium (building block of 3 alike components)"
  );

  it.todo(
    "quote for 4 runes should have 100 G base premium (4 x 25 G, no block -- block requires exactly 3)"
  );

  it.todo(
    "quote for 7 runes should have 175 G base premium (7 x 25 G, no block)"
  );

  it.todo(
    "quote for 2 runes + 1 moonstone should have 75 G base premium (no block: different types)"
  );

  it.todo(
    "quote for 3 runes + 3 moonstones should have 120 G base premium (two separate blocks of 3)"
  );

  // ── Quote: Item-Specific Modifiers ────────────────────────────────

  it.todo(
    "quote for a cursed sword should add 50% curse surcharge to the sword's base premium only"
  );

  it.todo(
    "quote for a sword with enchantment 5 should add 30% high-enchantment surcharge"
  );

  it.todo(
    "quote for a sword with enchantment 4 should NOT add high-enchantment surcharge"
  );

  it.todo(
    "quote for a cursed sword with enchantment 5 should add both 50% curse and 30% enchantment surcharges"
  );

  it.todo(
    "quote for a cursed sword + plain amulet should apply curse surcharge only to the sword -- 210 G before fee (100 + 50 curse + 60 amulet)"
  );

  // ── Quote: Policy-Wide Modifiers ──────────────────────────────────

  it.todo(
    "quote for a customer with exactly 2 years should apply 20% loyalty discount"
  );

  it.todo(
    "first insurance surcharge (+10%) always applies since each quote treats items as first insurance"
  );

  it.todo(
    "follow-up contract (-15%) applies when this is not the customer's first quote in the scenario"
  );

  // ── Quote: Integration Examples ───────────────────────────────────

  it.todo(
    "newcomer (0 years, first contract) with cursed sword (steel, ench 3) should return premium 165 G (100 + 50 curse + 10 first = 160 + 5 fee)"
  );

  it.todo(
    "long-standing (3 years, second contract) with cursed sword (steel, ench 7) should return premium 160 G (100 + 50 + 30 - 20 + 10 - 15 = 155 + 5 fee)"
  );

  // ── Quote: Rounding ───────────────────────────────────────────────

  it.todo(
    "premium that yields a fractional amount should round UP in MHPCO's favor (e.g., 197.5 -> 198 G)"
  );

  // ── Claim: Standard Reimbursement ─────────────────────────────────

  it.todo(
    "claim on regular sword (steel, ench 3), damage 500 G should pay out 400 G (full minus 100 G deductible)"
  );

  it.todo(
    "claim on a rune, damage 200 G should pay out 100 G (full minus 100 G deductible)"
  );

  // ── Claim: Enchantment >= 8 (50% Reimbursement) ───────────────────

  it.todo(
    "claim on steel sword (ench 9), damage 1000 G should pay out 400 G (50% = 500, minus 100 deductible)"
  );

  // ── Claim: Dragon Material ────────────────────────────────────────

  it.todo(
    "claim on dragon sword (ench 5), damage 800 G should pay out 700 G (dragon = full reimbursement, minus 100 deductible)"
  );

  // ── Claim: Both Clauses (Enchantment >= 8 AND Dragon Material) ────

  it.todo(
    "claim on dragon sword (ench 9), damage 1000 G should pay out 400 G (both clauses: 50% wins, then deductible: 500 - 100)"
  );

  it.todo(
    "claim on dragon sword (ench 8), damage 1000 G should pay out 400 G (high-enchantment clause applies at threshold, then deductible)"
  );

  // ── Claim: Deductible Per Damaged Item ────────────────────────────

  it.todo(
    "claim on sword (500 G damage) + amulet (300 G damage) should pay out 600 G (100 G deductible per item)"
  );

  // ── Claim: Payout Rounding ────────────────────────────────────────

  it.todo(
    "payout that yields a fractional amount should round DOWN in MHPCO's favor (e.g., 350.5 -> 350 G)"
  );

  // ── Claim: Cap ────────────────────────────────────────────────────

  it.todo(
    "policy with sword + amulet should have cap 3200 G (2 x (1000 + 600) insurance sum)"
  );

  it.todo(
    "cap is based on unmodified insurance value -- cursed sword cap is 2000 G regardless of premium modifiers"
  );

  it.todo(
    "policy with sword + 3 runes (block) should have insurance sum 1750 G (1000 + 3x250); block discount affects premium only, not insurance sum"
  );

  it.todo(
    "two successive claims of 1500 G on a sword policy (cap 2000): first payout 1400 G (remaining 600), second payout 600 G (remaining 0)"
  );

  // ── Claim: Multiple Items of Same Type ────────────────────────────

  it.todo(
    "policy with two swords should have insurance sum 2000 G and cap 4000 G"
  );

  it.todo(
    "claim with two sword damage entries on a two-sword policy should apply separate deductibles to each"
  );

  // ── Edge Cases / Error Handling ───────────────────────────────────

  it.todo(
    "quote with an unknown item type (e.g., broomstick) should exit with non-zero status and error to stderr"
  );

  it.todo(
    "claim referencing an item not in the policy should exit with non-zero status and error to stderr"
  );

  it.todo(
    "claim with more damage entries of a type than insured items should exit with non-zero status and error to stderr"
  );

  it.todo(
    "claim with negative damage amount should exit with non-zero status and error to stderr"
  );
});
